/* Aladin OpenClaw Integration - Background Message Handler */
try { importScripts("config.js", "scripts/auth0.js"); } catch(e) { console.warn("Aladin: config/auth0 import skipped", e); }
(function(){
  const OPENCLAW_DEFAULT_GATEWAY = (typeof globalThis !== "undefined" && globalThis.ALADIN_CONFIG && globalThis.ALADIN_CONFIG.SERVER_URL) || "http://localhost:3001";
  
  async function getOpenClawConfig() {
    const result = await chrome.storage.local.get([
      "openclaw_gateway_url", "openclaw_api_token", "openclaw_agent_id"
    ]);
    return {
      gatewayUrl: result.openclaw_gateway_url || OPENCLAW_DEFAULT_GATEWAY,
      apiToken: result.openclaw_api_token || "",
      agentId: result.openclaw_agent_id || "main"
    };
  }

  function openclawHeaders(token) {
    const h = { "Content-Type": "application/json" };
    if (token) h["Authorization"] = "Bearer " + token;
    return h;
  }

  async function openclawChat(messages, stream) {
    const cfg = await getOpenClawConfig();
    const resp = await fetch(cfg.gatewayUrl + "/v1/chat/completions", {
      method: "POST",
      headers: Object.assign(openclawHeaders(cfg.apiToken), {"x-openclaw-agent-id": cfg.agentId}),
      body: JSON.stringify({ model: "openclaw", messages: messages, stream: !!stream })
    });
    if (!resp.ok) throw new Error("OpenClaw " + resp.status);
    return stream ? resp.body : resp.json();
  }

  async function openclawToolInvoke(tool, args) {
    const cfg = await getOpenClawConfig();
    const resp = await fetch(cfg.gatewayUrl + "/tools/invoke", {
      method: "POST",
      headers: openclawHeaders(cfg.apiToken),
      body: JSON.stringify({ tool: tool, action: "json", args: args || {}, sessionKey: "main" })
    });
    if (!resp.ok) throw new Error("OpenClaw tool " + resp.status);
    return resp.json();
  }

  async function capturePageContext(tabId) {
    try {
      await chrome.scripting.executeScript({
        target: { tabId: tabId },
        files: ["scripts/accessibilityTree.js"]
      });
    } catch(e) {}
    const [result] = await chrome.scripting.executeScript({
      target: { tabId: tabId },
      func: function() {
        if (typeof window.__generateAccessibilityTree === "function") {
          return window.__generateAccessibilityTree("all", 10, 50000);
        }
        return { pageContent: (document.body && document.body.innerText || "").substring(0, 10000) };
      }
    });
    const tab = await chrome.tabs.get(tabId);
    return {
      url: tab.url, title: tab.title,
      pageContent: (result && result.result && result.result.pageContent) || "",
      viewport: (result && result.result && result.result.viewport) || {}
    };
  }

  chrome.runtime.onMessage.addListener(function(message, sender, sendResponse) {
    if (message.type === "GEODO_SCREEN_CONTEXT") {
      (async function() {
        try {
          const tabId = message.tabId || (sender.tab && sender.tab.id);
          if (!tabId) { sendResponse({error: "No tab ID"}); return; }
          const ctx = await capturePageContext(tabId);
          const sysMsg = "You are Aladin, an AI assistant that understands everything the user sees on their screen.\n" +
            "URL: " + ctx.url + "\nTitle: " + ctx.title + "\n" +
            "Viewport: " + (ctx.viewport.width||0) + "x" + (ctx.viewport.height||0) + "\n\n" +
            "Page content (accessibility tree):\n" + ctx.pageContent;
          const msgs = [
            { role: "system", content: sysMsg },
            { role: "user", content: message.userMessage || "What am I looking at? Summarize this page." }
          ];
          const resp = await openclawChat(msgs, false);
          sendResponse({ ok: true, data: resp });
        } catch(e) {
          sendResponse({ ok: false, error: e.message });
        }
      })();
      return true;
    }
    if (message.type === "GEODO_OPENCLAW_CHAT") {
      (async function() {
        try {
          const resp = await openclawChat(message.messages, false);
          sendResponse({ ok: true, data: resp });
        } catch(e) {
          sendResponse({ ok: false, error: e.message });
        }
      })();
      return true;
    }
    if (message.type === "GEODO_OPENCLAW_TOOL") {
      (async function() {
        try {
          const resp = await openclawToolInvoke(message.tool, message.args);
          sendResponse({ ok: true, data: resp });
        } catch(e) {
          sendResponse({ ok: false, error: e.message });
        }
      })();
      return true;
    }
    if (message.type === "GEODO_TEST_CONNECTION") {
      (async function() {
        try {
          const cfg = await getOpenClawConfig();
          const resp = await fetch(cfg.gatewayUrl + "/tools/invoke", {
            method: "POST",
            headers: openclawHeaders(cfg.apiToken),
            body: JSON.stringify({ tool: "sessions_list", action: "json", args: {} })
          });
          sendResponse({ ok: resp.ok, status: resp.status });
        } catch(e) {
          sendResponse({ ok: false, error: e.message });
        }
      })();
      return true;
    }
    if (message.type === "GEODO_SAVE_CONFIG") {
      chrome.storage.local.set({
        openclaw_gateway_url: message.gatewayUrl,
        openclaw_api_token: message.apiToken,
        openclaw_agent_id: message.agentId
      }).then(function() { sendResponse({ok:true}); });
      return true;
    }
    if (message.type === "GEODO_GET_CONFIG") {
      getOpenClawConfig().then(function(cfg) { sendResponse({ok:true, data:cfg}); });
      return true;
    }
  });

  globalThis.__aladinOpenClaw = {
    chat: openclawChat,
    tool: openclawToolInvoke,
    capturePageContext: capturePageContext,
    getConfig: getOpenClawConfig
  };

  // Auth0 message handlers
  chrome.runtime.onMessage.addListener(function(message, sender, sendResponse) {
    if (message.type === "ALADIN_AUTH_LOGIN") {
      if (typeof AladinAuth === "undefined") { sendResponse({ok:false,error:"Auth0 not loaded"}); return true; }
      AladinAuth.login()
        .then(function(result) { sendResponse({ok:true,data:result}); })
        .catch(function(e) { sendResponse({ok:false,error:e.message}); });
      return true;
    }
    if (message.type === "ALADIN_AUTH_LOGOUT") {
      if (typeof AladinAuth === "undefined") { sendResponse({ok:false,error:"Auth0 not loaded"}); return true; }
      AladinAuth.logout()
        .then(function(result) { sendResponse({ok:true,data:result}); })
        .catch(function(e) { sendResponse({ok:false,error:e.message}); });
      return true;
    }
    if (message.type === "ALADIN_AUTH_GET_TOKEN") {
      if (typeof AladinAuth === "undefined") { sendResponse({ok:false,error:"Auth0 not loaded"}); return true; }
      AladinAuth.getAccessToken()
        .then(function(token) { sendResponse({ok:true,data:{accessToken:token}}); })
        .catch(function(e) { sendResponse({ok:false,error:e.message}); });
      return true;
    }
    if (message.type === "ALADIN_AUTH_GET_USER") {
      if (typeof AladinAuth === "undefined") { sendResponse({ok:false,error:"Auth0 not loaded"}); return true; }
      AladinAuth.getUser()
        .then(function(user) { sendResponse({ok:true,data:{user:user}}); })
        .catch(function(e) { sendResponse({ok:false,error:e.message}); });
      return true;
    }
    if (message.type === "ALADIN_AUTH_STATUS") {
      if (typeof AladinAuth === "undefined") { sendResponse({ok:true,data:{loggedIn:false}}); return true; }
      AladinAuth.isLoggedIn()
        .then(function(loggedIn) { sendResponse({ok:true,data:{loggedIn:loggedIn}}); })
        .catch(function(e) { sendResponse({ok:false,error:e.message}); });
      return true;
    }
    if (message.type === "ALADIN_AUTH_SAVE_CONFIG") {
      if (typeof AladinAuth === "undefined") { sendResponse({ok:false,error:"Auth0 not loaded"}); return true; }
      AladinAuth.saveAuthConfig({
        domain: message.domain,
        clientId: message.clientId,
        audience: message.audience
      }).then(function() { sendResponse({ok:true}); });
      return true;
    }
  });
})();
